## File 1: `run_report.py`

```python
import os,sys,glob
from datetime import datetime
for p in["pandas","openpyxl","xlsxwriter"]:
 try:__import__(p)
 except:os.system(f"{sys.executable} -m pip install {p}")
import pandas as pd
import warnings
warnings.filterwarnings("ignore")
folder=os.path.dirname(os.path.abspath(__file__))
files=[f for f in glob.glob(os.path.join(folder,"*.xlsx"))+glob.glob(os.path.join(folder,"*.xls"))+glob.glob(os.path.join(folder,"*.xlsm")) if not os.path.basename(f).startswith("REPORT_")]
if not files:input("❌ No Excel files found next to this script. Press Enter to close.");sys.exit(1)
all_dfs=[]
for f in files:
 try:
  for n,df in pd.read_excel(f,sheet_name=None,engine="openpyxl").items():
   if len(df)>0 and len(df.columns)>=2:df["_source"]=os.path.basename(f);all_dfs.append(df)
 except:pass
if not all_dfs:input("❌ No usable data found. Press Enter to close.");sys.exit(1)
combined=pd.concat(all_dfs,ignore_index=True,sort=False)
nc,dc,tc=[],[],[]
for col in[c for c in combined.columns if not c.startswith("_")]:
 if pd.api.types.is_numeric_dtype(combined[col]):nc.append(col);continue
 cl=combined[col].astype(str).str.replace(r'[$€£,\s]','',regex=True)
 try:
  cv=pd.to_numeric(cl,errors='coerce')
  if cv.notna().sum()/max(len(combined),1)>.5:combined[col]=cv;nc.append(col);continue
 except:pass
 try:
  cv=pd.to_datetime(combined[col],errors='coerce',infer_datetime_format=True)
  if cv.notna().sum()/max(len(combined),1)>.5:combined[col]=cv;dc.append(col);continue
 except:pass
 nu=combined[col].nunique()
 if 1<nu<len(combined)*.5:tc.append(col)
rc=next((c for c in nc if any(k in c.lower() for k in["revenue","sales","income","amount","total","price","gross"])),None)
cc=next((c for c in nc if c!=rc and any(k in c.lower() for k in["cost","expense","spend","cogs"])),None)
hp=rc and cc
R={}
t=[]
for c in nc:t+=[ {"Metric":f"Total {c}","Value":combined[c].sum()},{"Metric":f"Average {c}","Value":round(combined[c].mean(),2)}]
t+=[{"Metric":"Total Rows","Value":len(combined)},{"Metric":"Files Processed","Value":len(files)},{"Metric":"Report Generated","Value":datetime.now().strftime("%Y-%m-%d %H:%M")}]
R["Grand Totals"]=pd.DataFrame(t)
for tc_ in tc:
 try:
  s=combined.groupby(tc_,as_index=False)[nc].sum()
  if hp:s["Profit"]=s[rc]-s[cc];s["Margin %"]=((s["Profit"]/s[rc])*100).round(2).fillna(0)
  s=s.sort_values(nc[0],ascending=False)if nc else s
  R[f"By {tc_}"[:31]]=s
 except:pass
if len(tc)>=2 and nc:
 try:
  cr=combined.groupby(tc[:2],as_index=False)[nc].sum()
  if hp:cr["Profit"]=cr[rc]-cr[cc];cr["Margin %"]=((cr["Profit"]/cr[rc])*100).round(2).fillna(0)
  R["Cross Summary"]=cr
 except:pass
if dc:
 try:
  combined["_M"]=combined[dc[0]].dt.to_period("M").astype(str)
  m=combined.groupby("_M",as_index=False)[nc].sum()
  if hp:m["Profit"]=m[rc]-m[cc];m["Margin %"]=((m["Profit"]/m[rc])*100).round(2).fillna(0)
  for c in nc[:3]:m[f"{c} MoM%"]=(m[c].pct_change()*100).round(2)
  R["Monthly Trend"]=m.sort_values("_M").rename(columns={"_M":"Month"})
 except:pass
if tc and nc:
 try:
  rk=combined.groupby(tc[0],as_index=False)[nc].sum().sort_values(nc[0],ascending=False)
  if len(rk)>10:R["Top 10"]=rk.head(10);R["Bottom 10"]=rk.tail(10)
 except:pass
try:R["By Source File"]=combined.groupby("_source",as_index=False).agg(Rows=("_source","count"),**{f"Total {c}":(c,"sum") for c in nc[:6]})
except:pass
R["All Data"]=combined.drop(columns=[c for c in combined.columns if c.startswith("_")],errors="ignore")
out=os.path.join(folder,f"REPORT_{datetime.now().strftime('%Y%m%d_%H%M%S')}.xlsx")
with pd.ExcelWriter(out,engine="xlsxwriter") as w:
 wb=w.book;hf=wb.add_format({"bold":True,"bg_color":"#2F5496","font_color":"white","border":1});tf=wb.add_format({"bold":True,"font_size":14,"font_color":"#2F5496"})
 for sn,df in R.items():
  s=sn[:31];df.to_excel(w,sheet_name=s,index=False,startrow=1);ws=w.sheets[s];ws.write(0,0,sn,tf)
  for i,cn in enumerate(df.columns):ws.write(1,i,cn,hf);ws.set_column(i,i,min(max(len(str(cn)),df[cn].astype(str).str.len().max() if len(df) else 5)+3,45))
  ws.freeze_panes(2,0);ws.autofilter(1,0,len(df),len(df.columns)-1)
print(f"\n✅ REPORT SAVED: {out}")
input("\nDone! Press Enter to close.")
```

## File 2: `RUN_REPORT.bat`

```bat
@echo off
cd /d "%~dp0"
python run_report.py
if errorlevel 1 (
    echo.
    echo Python not found. Trying py launcher...
    py run_report.py
)
if errorlevel 1 (
    echo.
    echo ❌ Python is not installed. Install from python.org and try again.
    pause
)
```

## What to do right now

1. **Make a folder** anywhere (Desktop is fine)
2. **Copy your Excel files** into it
3. **Save both files above** into that same folder
4. **Double-click `RUN_REPORT.bat`**
5. A file called `REPORT_20250614_XXXXXX.xlsx` appears in the same folder — **that's your deliverable**
